const GOD_BY_SLUG: Record<string, CelticGuide> = Object.fromEntries(CELTIC_GODS.map((g) => [g.slug, g]))

export const CELTIC_GOD_SLUGS = CELTIC_GODS.map((g) => g.slug)

export function isCelticGodSlug(s: string): boolean {
  return s in GOD_BY_SLUG
}

