          { '@type': 'ListItem', position: 2, name: 'Celtic Gods', item: `${SITE_URL}/gab44/celtic-gods` },
          { '@type': 'ListItem', position: 3, name: r.text, item: `${SITE_URL}/gab44/celtic-gods/${slug}` }
